mapper.select:
SELECT 
    s.*,
    c.name AS clazz_name
FROM student s
LEFT JOIN clazz c ON s.clazz_id = c.id


        AND s.name LIKE CONCAT('%', #{name}, '%')


        AND s.gender = #{gender}


        AND s.phone LIKE CONCAT('%', #{phone}, '%')


        AND s.no LIKE CONCAT('%', #{no}, '%')


        AND s.clazz_id = #{clazzId}


        AND s.graduation_date >= #{beginGraduationDate}


        AND s.graduation_date <= #{endGraduationDate}


ORDER BY s.create_time DESC

SELECT COUNT(*)
FROM student
WHERE clazz_id = #{clazz_id}
